15 CSS Tricks That Save Me Hours Every Week


Not animations or fancy effects. Practical solutions to real layout problems.
/* Single line */
.truncate {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Multi-line (works in modern browsers) */
.truncate-2 {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* Flexbox — works for everything */
.center {
  display: flex;
  justify-content: center; /* horizontal */
  align-items: center;     /* vertical */
  min-height: 100vh;
}

/* Grid — even simpler */
.center {
  display: grid;
  place-items: center;
  min-height: 100vh;
}

/* Stays visible when scrolling */
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: white; /* Important: opaque background */
}

.sticky-footer {
  position: sticky;
  bottom: 0;
}

/* Webkit browsers (Chrome, Safari, Edge) */
.custom-scrollbar::-webkit-scrollbar {
  width: 8px;
}

.custom-scrollbar::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 4px;
}

.custom-scrollbar::-webkit-scrollbar-thumb {
  background: #c1c1c1;
  border-radius: 4px;
}

.custom-scrollbar::-webkit-scrollbar-thumb:hover {
  background: #a1a1a1;
}

/* Before: padding-bottom hack (ugly) */
.aspect-old {
  position: relative;
  padding-bottom: 56.25%; /* 16:9 */
}

/* Now: aspect-ratio property */
.video-container {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: black;
}

.square {
  aspect-ratio: 1 / 1;
}

/* Entire page */
html {
  scroll-behavior: smooth;
}

/* Or specific container */
.scroll-container {
  scroll-behavior: smooth;
  overflow-y: auto;
  max-height: 400px;
}

::selection {
  background: #3b82f6; /* Blue */
  color: white;
}

/* Brand-colored selection looks professional */

/* Show focus ring only when using keyboard, not mouse click */
:focus-visible {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}

